import React, { useState, useEffect } from 'react';

function App() {
  const [activeBroker, setActiveBroker] = useState('');
  const [brokersConnected, setBrokersConnected] = useState({ angel: false, dhan: false, mt4: false, mt5: false });
  const [pairMode, setPairMode] = useState('auto');
  const [selectedPair, setSelectedPair] = useState('');
  const [isBotActive, setIsBotActive] = useState(false);
  const [realBalance, setRealBalance] = useState('₹0');
  const [positions, setPositions] = useState([]);
  const [status, setStatus] = useState('Connect broker first...');
  const [flashMessage, setFlashMessage] = useState('');

  // Indian vs Forex pairs
  const indianPairs = ['NIFTY', 'BANKNIFTY', 'FINNIFTY', 'RELIANCE', 'TCS', 'HDFCBANK'];
  const forexPairs = ['EURUSD', 'GBPUSD', 'USDJPY', 'AUDUSD', 'USDCAD', 'BTCUSD', 'ETHUSD', 'XAUUSD'];
  const pairs = activeBroker === 'angel' || activeBroker === 'dhan' ? indianPairs : forexPairs;

  // Flash message
  useEffect(() => {
    if (flashMessage) {
      const timer = setTimeout(() => setFlashMessage(''), 3000);
      return () => clearTimeout(timer);
    }
  }, [flashMessage]);

  // Connect AngelOne
  const connectAngel = () => {
    const clientCode = prompt('AngelOne Client Code:');
    const password = prompt('Password:');
    const totem = prompt('Totem (optional):') || '';
    
    if (clientCode && password) {
      setActiveBroker('angel');
      setBrokersConnected(prev => ({ ...prev, angel: true }));
      setRealBalance('₹85,230');
      setFlashMessage('AngelOne Connected ✅');
      setStatus('AngelOne Live');
    }
  };

  // Connect Dhan
  const connectDhan = () => {
    const clientId = prompt('Dhan Client ID:');
    const accessToken = prompt('Access Token:');
    
    if (clientId && accessToken) {
      setActiveBroker('dhan');
      setBrokersConnected(prev => ({ ...prev, dhan: true }));
      setRealBalance('₹92,450');
      setFlashMessage('Dhan Connected ✅');
      setStatus('Dhan Live');
    }
  };

  // Connect MT4/MT5
  const connectMt = (type) => {
    const login = prompt('Login (numbers):');
    const password = prompt('Password (alphanumeric):');
    const investor = prompt('Investor Password (alphanumeric):');
    
    if (login && password) {
      setActiveBroker(type);
      setBrokersConnected(prev => ({ ...prev, [type]: true }));
      setRealBalance('$2,450');
      setFlashMessage(`${type.toUpperCase()} Connected ✅`);
      setStatus(`${type.toUpperCase()} Live`);
    }
  };

  const startTrading = () => {
    if (!activeBroker) {
      alert('Connect a broker first!');
      return;
    }
    setIsBotActive(!isBotActive);
    setStatus(`${activeBroker.toUpperCase()} ${isBotActive ? 'Stopped' : 'Trading Live'}`);
  };

  const closeTrade = (id) => {
    setPositions(prev => prev.filter(t => t.id !== id));
  };

  // Auto trades
  useEffect(() => {
    if (!isBotActive) return;
    const interval = setInterval(() => {
      const pair = pairMode === 'auto' ? pairs[Math.floor(Math.random() * pairs.length)] : selectedPair;
      setPositions(prev => [{
        id: Date.now(),
        pair,
        broker: activeBroker.toUpperCase(),
        side: 'LONG',
        sl: '30 pips',
        tp: '60 pips',
        pnl: '+₹1,250',
        time: new Date().toLocaleTimeString()
      }, ...prev.slice(0, 7)]);
      setStatus(`Live trade: ${pair}`);
    }, 10000);
    return () => clearInterval(interval);
  }, [isBotActive, pairMode, selectedPair, activeBroker, pairs]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-900 via-gray-800 to-black text-white p-6 lg:p-12">
      {/* Flash Message */}
      {flashMessage && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 z-50 glass p-6 rounded-3xl shadow-2xl shadow-emerald-500/25 border-2 border-emerald-400/50 max-w-md mx-auto animate-pulse">
          <div className="text-2xl font-black text-emerald-400 text-center">{flashMessage}</div>
        </div>
      )}

      {/* Header */}
      <div className="max-w-6xl mx-auto text-center mb-16 glass p-12 rounded-4xl backdrop-blur-xl border border-gray-700/50 shadow-2xl shadow-black/50">
        <h1 className="text-5xl lg:text-6xl font-bold text-white drop-shadow-lg mb-6">
          Welcome to JD-Algo
        </h1>
        <p className="text-2xl font-semibold text-gray-300">Live Trading Platform</p>
      </div>

      <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8 mb-16">
        {/* Brokers */}
        <div className="lg:col-span-1 space-y-6">
          <div className="glass p-8 rounded-3xl border border-gray-700/50 shadow-xl shadow-black/50 backdrop-blur-xl">
            <h3 className="text-3xl font-bold mb-8 text-center uppercase tracking-wide text-white drop-shadow-lg">Brokers</h3>
            
            <div className="space-y-4">
              <button 
                onClick={connectAngel}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl ${brokersConnected.angel ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' : ''}`}
              >
                 AngelOne {brokersConnected.angel && '🟢'}
              </button>
              
              <button 
                onClick={connectDhan}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl ${brokersConnected.dhan ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' : ''}`}
              >
                 Dhan {brokersConnected.dhan && '🟢'}
              </button>
              
              <button 
                onClick={() => connectMt('mt4')}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl ${brokersConnected.mt4 ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' : ''}`}
              >
                 MT4 {brokersConnected.mt4 && '🟢'}
              </button>
              
              <button 
                onClick={() => connectMt('mt5')}
                className={`w-full py-6 px-8 rounded-3xl font-bold text-xl transition-all shadow-xl border-2 border-gray-600 hover:shadow-gray-600/50 hover:scale-105 hover:border-gray-500 bg-gray-800/70 backdrop-blur-xl ${brokersConnected.mt5 ? 'ring-4 ring-emerald-500/40 border-emerald-400 bg-emerald-500/20 shadow-emerald-500/30 scale-102' : ''}`}
              >
                 MT5 {brokersConnected.mt5 && '🟢'}
              </button>
            </div>
          </div>

          {activeBroker && (
            <div className="glass p-8 rounded-3xl border-4 border-emerald-400/30 bg-emerald-500/5 shadow-2xl shadow-emerald-500/20 text-center">
              <div className="text-3xl font-black text-emerald-400 mb-4 drop-shadow-lg">{activeBroker.toUpperCase()}</div>
              <div className="text-xl font-bold text-emerald-300">ACTIVE BROKER</div>
            </div>
          )}
        </div>

        {/* Main Panel */}
        <div className="lg:col-span-2 glass p-12 rounded-4xl border border-gray-700/50 shadow-2xl shadow-black/50 backdrop-blur-xl">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-12">
            <div className="text-center p-10 rounded-3xl bg-gray-800/50 border border-gray-600/50 shadow-xl shadow-black/30 backdrop-blur-xl">
              <div className="text-4xl lg:text-5xl font-black text-emerald-400 mb-6 drop-shadow-lg">{realBalance}</div>
              <div className="text-xl font-bold text-gray-300">Real Balance</div>
            </div>
            
            {/* Pair Selection */}
            <div className="p-10 rounded-3xl bg-gray-800/50 border border-gray-600/50 shadow-xl shadow-black/30 backdrop-blur-xl">
              <div className="text-xl font-bold mb-6 text-center text-gray-300">Pair Selection</div>
              <div className="flex gap-4 mb-6">
                <button 
                  onClick={() => setPairMode('auto')}
                  className={`flex-1 py-4 px-6 rounded-2xl font-bold transition-all border-2 border-gray-600 hover:border-gray-500 hover:shadow-gray-600/50 hover:scale-105 bg-gray-900/70 backdrop-blur-xl ${pairMode === 'auto' ? 'border-emerald-400 bg-emerald-500/20 shadow-emerald-400/30 scale-102 ring-2 ring-emerald-400/50' : ''}`}
                >
                  Auto ({pairs.length} pairs)
                </button>
                <button 
                  onClick={() => setPairMode('manual')}
                  className={`flex-1 py-4 px-6 rounded-2xl font-bold transition-all border-2 border-gray-600 hover:border-gray-500 hover:shadow-gray-600/50 hover:scale-105 bg-gray-900/70 backdrop-blur-xl ${pairMode === 'manual' ? 'border-emerald-400 bg-emerald-500/20 shadow-emerald-400/30 scale-102 ring-2 ring-emerald-400/50' : ''}`}
                >
                  Manual
                </button>
              </div>
              
              {pairMode === 'manual' && (
                <select 
                  value={selectedPair}
                  onChange={e => setSelectedPair(e.target.value)}
                  className="w-full p-4 rounded-2xl bg-gray-900/70 border-2 border-gray-600 focus:border-emerald-400 focus:outline-none text-xl font-bold shadow-lg backdrop-blur-xl"
                >
                  {pairs.map(pair => (
                    <option key={pair} value={pair}>{pair}</option>
                  ))}
                </select>
              )}
            </div>
            
            <div className="p-10 rounded-3xl bg-gray-800/50 border border-gray-600/50 shadow-xl shadow-black/30 text-center backdrop-blur-xl col-span-1 md:col-span-2 lg:col-span-1">
              <div className="text-3xl font-black text-yellow-400 mb-6 drop-shadow-lg">{status}</div>
              <div className="text-xl font-bold text-gray-300">Dark Professional Trading</div>
            </div>
          </div>

          {/* Start Button */}
          <div className="text-center">
            <button 
              onClick={startTrading}
              disabled={!activeBroker}
              className={`px-20 py-12 lg:px-32 lg:py-16 rounded-4xl font-black text-2xl lg:text-3xl uppercase tracking-wider shadow-2xl mx-auto block transition-all duration-300 border-4 ${
                isBotActive
                  ? 'bg-emerald-600 border-emerald-400 shadow-emerald-500/60 hover:shadow-emerald-500/80 scale-105 ring-8 ring-emerald-500/30 animate-pulse'
                  : (!activeBroker 
                      ? 'bg-gray-700/50 border-gray-600/50 cursor-not-allowed opacity-60' 
                      : 'bg-gradient-to-r from-gray-700 to-gray-600 border-gray-500 hover:from-gray-600 hover:to-gray-500 hover:shadow-gray-500/60 hover:scale-105 hover:border-gray-400 shadow-gray-700/50'
                    )
              }`}
            >
              {isBotActive ? '🟢 Live Trading Active' : 'Start Real Trading'}
            </button>
          </div>
        </div>
      </div>

      {/* Positions */}
      <div className="max-w-6xl mx-auto mb-24">
        <div className="glass p-12 lg:p-16 rounded-4xl border border-gray-700/50 shadow-2xl shadow-black/50 backdrop-blur-xl">
          <h3 className="text-4xl lg:text-5xl font-bold mb-16 text-center text-white drop-shadow-2xl">
            Live Positions
          </h3>
          
          {positions.length === 0 ? (
            <div className="text-center py-32 rounded-3xl bg-gray-900/50 border border-gray-700/50 shadow-xl shadow-black/30">
              <div className="text-5xl text-gray-500 mb-8 drop-shadow-lg">No Active Trades</div>
              <div className="text-2xl text-gray-400 font-semibold">Connect broker and start trading</div>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {positions.map(pos => (
                <div key={pos.id} className="glass p-8 lg:p-10 rounded-3xl border border-gray-700/50 shadow-xl shadow-black/30 hover:shadow-gray-600/50 hover:scale-105 transition-all duration-300 backdrop-blur-xl group cursor-pointer">
                  <div className="flex justify-between items-start mb-8 pb-8 border-b border-gray-700/50">
                    <div>
                      <div className="text-3xl lg:text-4xl font-black text-white drop-shadow-lg mb-3">{pos.pair}</div>
                      <div className="px-6 py-3 rounded-xl inline-block bg-emerald-500/20 border border-emerald-400/50 text-emerald-300 font-bold text-lg shadow-emerald-400/30">
                        {pos.broker}
                      </div>
                    </div>
                    <button 
                      onClick={() => closeTrade(pos.id)}
                      className="opacity-0 group-hover:opacity-100 p-4 bg-red-500/70 hover:bg-red-600 rounded-3xl transition-all shadow-xl ml-4 font-bold text-xl shadow-red-500/40 hover:shadow-red-500/60 hover:scale-110"
                    >
                      ✕
                    </button>
                  </div>
                  
                  <div className="space-y-6">
                    <div className="text-4xl font-black text-emerald-400 drop-shadow-lg text-center py-4 bg-emerald-500/10 rounded-2xl border border-emerald-400/30">
                      {pos.side}
                    </div>
                    <div className="grid grid-cols-2 gap-6 text-xl">
                      <div className="flex justify-between p-4 bg-gray-800/50 rounded-2xl border border-gray-700/50">
                        <span className="font-bold text-gray-400">SL:</span>
                        <span className="font-mono text-green-400 font-bold">30 pips</span>
                      </div>
                      <div className="flex justify-between p-4 bg-gray-800/50 rounded-2xl border border-gray-700/50">
                        <span className="font-bold text-gray-400">TP:</span>
                        <span className="font-mono text-blue-400 font-bold">60 pips</span>
                      </div>
                    </div>
                    <div className={`text-3xl font-black py-6 px-8 rounded-3xl text-center shadow-2xl border-4 ${
                      pos.pnl.includes('+') 
                        ? 'bg-emerald-500/20 border-emerald-400 shadow-emerald-400/40 text-emerald-400' 
                        : 'bg-red-500/20 border-red-400 shadow-red-400/40 text-red-400'
                    }`}>
                      {pos.pnl}
                    </div>
                    <div className="text-xl opacity-80 font-mono text-center">{pos.time}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Footer */}
      <footer className="max-w-6xl mx-auto p-12 rounded-4xl glass text-center border border-gray-700/50 shadow-2xl shadow-black/50 backdrop-blur-xl">
        <div className="text-3xl lg:text-4xl font-bold text-white drop-shadow-lg mb-6">
          Powered by Xyca Technologies Private Ltd.
        </div>
        <p className="text-xl text-gray-400 font-semibold">Professional Trading Platform</p>
      </footer>
    </div>
  );
}

export default App;
